const listAccounts = `-- name: ListAccounts :many
SELECT id, tenant_id, display_name, email, employee_id, status, user_group_ids, direct_permission_set_ids, active_assumable_role_id, created_at FROM accounts
WHERE tenant_id = $1
ORDER BY created_at ASC
`

func (q *Queries) ListAccounts(ctx context.Context, tenantID string) ([]Account, error) {
	rows, err := q.db.Query(ctx, listAccounts, tenantID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []Account
	for rows.Next() {
		var i Account
		if err := rows.Scan(
			&i.ID,
			&i.TenantID,
			&i.DisplayName,
			&i.Email,
			&i.EmployeeID,
			&i.Status,
			&i.UserGroupIds,
			&i.DirectPermissionSetIds,
			&i.ActiveAssumableRoleID,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

